const allInputs = $input.all();
const comprehensiveData = {};
let globalComment = "";

// 1. Metadata Safety Net (Grab data directly from Webhook node)
let metadata = {};
try {
  // Try Method 1: $items() lookup (Standard n8n)
  const webhookNode = $items("Webhook")[0].json;
  const b = webhookNode.body || webhookNode;
  metadata = { 
    domain: b.domain, 
    paciensId: b.PaciensID, 
    email: b.flexi_email, 
    password: b.flexi_password 
  };
} catch (e) {
  try {
    // Try Method 2: Global Object lookup
    const b = $node["Webhook"].json.body || $node["Webhook"].json;
    metadata = { 
      domain: b.domain, 
      paciensId: b.PaciensID, 
      email: b.flexi_email, 
      password: b.flexi_password 
    };
  } catch (e2) {}
}

// 2. Merge all quadrants and comments
allInputs.forEach((item) => {
  const data = item.json || {};
  if (data.section === "MEGJEGYZES_FO") {
    if (data.content) globalComment = globalComment ? `${globalComment}\n${data.content}` : data.content;
  }
  for (const [key, value] of Object.entries(data)) {
    if (/^\d{2}$/.test(key)) comprehensiveData[key] = value;
    if (['MEGJEGYZES_FO', 'megjegyzes_fo'].includes(key)) {
       if (typeof value === 'string' && value.trim()) globalComment = globalComment ? `${globalComment}\n${value}` : value;
    }
  }
});

// 3. Return combined object for Python
return [{ 
  json: {
    ...comprehensiveData,
    MEGJEGYZES_FO: globalComment,
    metadata: metadata
  } 
}];
